    tlen = __int32_t_decode_array(buf, offset + pos, maxlen - pos, &this->operation, 1);
    if(tlen < 0) return tlen; else pos += tlen;

    tlen = __double_decode_array(buf, offset + pos, maxlen - pos, &this->totalcurrent, 1);
