uint64_t Vehicle::_computeHash(const __lcm_hash_ptr *p)
{
    const __lcm_hash_ptr *fp;
    for(fp = p; fp != NULL; fp = fp->parent)
        if(fp->v == Vehicle::getHash)
            return 0;
    const __lcm_hash_ptr cp = { p, Vehicle::getHash };

    uint64_t hash = 0xd2d7da1cb945995eLL +
         lcm_interface::Header::_computeHash(&cp);

    return (hash<<1) + ((hash>>63)&1);
}

